// Package gpucheck provides functionality to check GPU support in container runtimes.
// Generated by Claude Sonnet 4
package gpucheck

import (
	"context"
	"fmt"
	"github.com/krkn-chaos/krknctl/pkg/config"
	"github.com/krkn-chaos/krknctl/pkg/provider/models"
	"github.com/krkn-chaos/krknctl/pkg/scenarioorchestrator"
	"strings"
	"time"
)

// Result represents the result of a GPU check
type Result struct {
	HasGPUSupport bool
	Output        string
	Error         error
}

// GpuChecker provides functionality to check GPU support
type GpuChecker struct {
	orchestrator scenarioorchestrator.ScenarioOrchestrator
	config       config.Config
}

// NewGpuChecker creates a new GPU checker instance
func NewGpuChecker(orchestrator scenarioorchestrator.ScenarioOrchestrator, config config.Config) *GpuChecker {
	return &GpuChecker{
		orchestrator: orchestrator,
		config:       config,
	}
}

// CheckGPUSupport runs a container to check GPU support in the container runtime
func (gc *GpuChecker) CheckGPUSupport(ctx context.Context, customImage string, registry *models.RegistryV2) (*Result, error) {
	// Determine which image to use
	image := customImage
	if image == "" {
		defaultImage, err := gc.config.GetGpuCheckImageURI()
		if err != nil {
			return &Result{
				HasGPUSupport: false,
				Error:         fmt.Errorf("failed to get default GPU check image URI: %w", err),
			}, err
		}
		image = defaultImage
	}

	// Generate unique container name
	containerName := fmt.Sprintf("krknctl-gpu-check-%d", time.Now().Unix())

	// Create communication channel for container output
	commChan := make(chan *string, 1)

	// Run the GPU check container
	containerID, err := gc.orchestrator.Run(
		image,
		containerName,
		map[string]string{}, // No special environment variables needed
		false,               // Don't cache
		map[string]string{}, // No volume mounts needed
		&commChan,
		ctx,
		registry,
	)

	if err != nil {
		return &Result{
			HasGPUSupport: false,
			Error:         fmt.Errorf("failed to run GPU check container: %w", err),
		}, err
	}

	// Wait for container output with timeout
	select {
	case output := <-commChan:
		if output == nil {
			return &Result{
				HasGPUSupport: false,
				Output:        "",
				Error:         fmt.Errorf("no output received from GPU check container"),
			}, nil
		}

		// Parse the output to determine GPU support
		hasGPU := parseGPUCheckOutput(*output)

		return &Result{
			HasGPUSupport: hasGPU,
			Output:        *output,
			Error:         nil,
		}, nil

	case <-time.After(30 * time.Second):
		// Cleanup: kill the container if it's still running
		if containerID != nil {
			_ = gc.orchestrator.Kill(containerID, ctx)
		}

		return &Result{
			HasGPUSupport: false,
			Error:         fmt.Errorf("timeout waiting for GPU check container output"),
		}, nil
	}
}

// parseGPUCheckOutput parses the container output to determine if GPU support is available
func parseGPUCheckOutput(output string) bool {
	// Look for success indicators in the output
	output = strings.ToLower(strings.TrimSpace(output))
	
	// Check for negative indicators first to handle cases like "no gpu detected"
	if strings.Contains(output, "gpu_check_failed") ||
		strings.Contains(output, "gpu support: no") ||
		strings.Contains(output, "no gpu detected") ||
		strings.Contains(output, "gpu not available") {
		return false
	}

	// Check for positive indicators
	if strings.Contains(output, "gpu_check_success") ||
		strings.Contains(output, "gpu support: yes") ||
		strings.Contains(output, "gpu detected") {
		return true
	}

	// Default to false if output is ambiguous
	return false
}

// FormatResult formats the GPU check result for CLI output
func (gc *GpuChecker) FormatResult(result *Result) string {
	if result.Error != nil {
		return "No"
	}

	if result.HasGPUSupport {
		return "Yes"
	}

	return "No"
}